        if(area.getMax() &gt; 0)&#123;
            rangeQueryBuilder.lte(area.getMax());
        &#125;
        if(area.getMin() &gt; 0)&#123;
            rangeQueryBuilder.gte(area.getMin());
        &#125;
        boolQuery.filter(rangeQueryBuilder);
    &#125;

    &#x2F;&#x2F;价格
