4数据接口您可通过数据接口获取详细的公交方案信息。公交导航搜索结果用BMap.TransitRouteResult来表示，其中包含了若干公交出行方案（BMap.TransitRoutePlan）。每条出行方案由步行线路和公交线路组成。 在起点到上车点之间、下车点到终点之间以及每个换乘站之间都会存在步行线路，如果上述的某两点位置重合，那么其间的步行路线长度为0。 如下示例，通过数据接口将第一条方案的路线添加到地图上。
var map &#x3D; new BMap.Map(&quot;container&quot;); 
map.centerAndZoom(new BMap.Point(116.404, 39.915), 12); 
var transit &#x3D; new BMap.TransitRoute(); 
transit.setSearchCompleteCallback(function(results) &#123; 
    if (transit.getStatus() &#x3D;&#x3D; BMAP_STATUS_SUCCESS) &#123; 
        var firstPlan &#x3D; results.getPlan(0); 
        &#x2F;&#x2F; 绘制步行线路 
        for (var i &#x3D; 0; i &lt; firstPlan.getNumRoutes(); i++) &#123; 
            var walk &#x3D; firstPlan.getRoute(i); 
            if (walk.getDistance(false) &gt; 0)&#123; 
                &#x2F;&#x2F; 步行线路有可能为0 
                map.addOverlay(new BMap.Polyline(walk.getPoints(), &#123;lineColor: &quot;green&quot;&#125;)); 
            &#125; 
        &#125; 
        &#x2F;&#x2F; 绘制公交线路 
        for (i &#x3D; 0; i &lt; firstPlan.getNumLines(); i++) &#123; 
                var line &#x3D; firstPlan.getLine(i); 
                map.addOverlay(new BMap.Polyline(line.getPoints())); 
        &#125;
    &#125; 
&#125;);
var start &#x3D; new BMap.Point(116.310791, 40.003419);
var end &#x3D; new BMap.Point(121.490546, 31.233585);
transit.search(start, end);

